from machine import I2C,UART,Pinfrom  Sengo2  import *import time# 等待Sengo2完成操作系统的初始化。此等待时间不可去掉，避免出现Sengo2尚未初始化完毕主控器已经开发发送指令的情况time.sleep(2)# 选择UART或者I2C通讯模式，Sengo2出厂默认为I2C模式，短按模式按键可以切换# 4种UART通讯模式：UART9600（标准协议指令），UART57600（标准协议指令），UART115200（标准协议指令），Simple9600（简单协议指令），########################################################################################################## port = UART(2,rx=Pin(16),tx=Pin(17),baudrate=9600)i2c = I2C(0,scl=Pin(22),sda=Pin(21),freq=400000)# Sengo2通讯地址：0x60。如果I2C总线挂接多个设备，请避免出现地址冲突sengo2 = Sengo2(0x60)err = sengo2.begin(i2c)print("sengo2.begin: 0x%x"% err)# 设置输出线段的数量，算法默认设置为1，最多检测5条sengo2.VisionSetMode(sengo2_vision_e.kVisionLine,4) # 1、算法文档# 2、请保持默认设置：只检测一条线段# 3、正常使用时，应由主控器发送指令控制Sengo2算法的开启与关闭，而非通过摇杆手动进行操作；# 4、满足特定限制条件下，Sengo2可以并行运行多个识别算法err = sengo2.VisionBegin(sengo2_vision_e.kVisionLine)print("sengo2.VisionBegin(sengo2_vision_e.kVisionLine):0x%x"% err)        while True:    # Sengo2不主动返回检测识别结果，需要主控板发送指令进行读取。读取的流程：首先读取识别结果的数量，接收到指令后，Sengo2会刷新结果数据，如果结果数量不为零，那么主控再发送指令读取结果的相关信息。请务必按此流程构建程序。    obj_num = sengo2.GetValue(sengo2_vision_e.kVisionLine, sentry_obj_info_e.kStatus)        if obj_num:        print(f"Totally {obj_num} lines detected")        for i in range(1,obj_num+1):            #获取线条角度（0-180度）           angle = sengo2.GetValue(sengo2_vision_e.kVisionLine,sentry_obj_info_e.kLabel,i)           #获取线条端点坐标           x1 = sengo2.GetValue(sengo2_vision_e.kVisionLine,sentry_obj_info_e.kXValue,i)           y1 = sengo2.GetValue(sengo2_vision_e.kVisionLine,sentry_obj_info_e.kYValue,i)           x2 = sengo2.GetValue(sengo2_vision_e.kVisionLine,sentry_obj_info_e.kWidthValue,i)           y2 = sengo2.GetValue(sengo2_vision_e.kVisionLine,sentry_obj_info_e.kHeightValue,i)           print("Line #%d: Start=(%d,%d), End(%d,%d), Angle=%d"%(i,x1,y1,x2,y2,angle))        time.sleep(0.2)        